import React from 'react';

const HowToDraftPleadings = () => {
  return (
    <div className="h-screen overflow-y-auto bg-gradient-to-br from-gray-900 via-slate-900 to-gray-900 p-8">
      <div className="max-w-6xl mx-auto space-y-8 pb-12">
        <h1 className="text-4xl font-bold text-white text-center sticky top-0 bg-gray-900/80 backdrop-blur-sm py-4 z-10">
          How to Draft Pleadings
        </h1>

        {/* Text Sections - Full Width */}
        <div className="space-y-8">
          {/* Título 1 - Full Width */}
          <div className="w-full bg-slate-800/40 backdrop-blur-sm rounded-xl p-6 border border-slate-700/50 hover:bg-slate-800/60 transition-all">
            <h2 className="text-2xl text-white mb-4">Título 1</h2>
            <p className="text-white text-[12px] leading-relaxed">
              Tu texto aquí
            </p>
          </div>

          {/* Título 2 - Full Width */}
          <div className="w-full bg-slate-800/40 backdrop-blur-sm rounded-xl p-6 border border-slate-700/50 hover:bg-slate-800/60 transition-all">
            <h2 className="text-2xl text-white mb-4">Título 2</h2>
            <p className="text-white text-[12px] leading-relaxed">
              Tu texto aquí
            </p>
          </div>

          {/* Título 3 - Full Width */}
          <div className="w-full bg-slate-800/40 backdrop-blur-sm rounded-xl p-6 border border-slate-700/50 hover:bg-slate-800/60 transition-all">
            <h2 className="text-2xl text-white mb-4">Título 3</h2>
            <p className="text-white text-[12px] leading-relaxed">
              Tu texto aquí
            </p>
          </div>

          {/* Remaining sections in grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Remaining text sections */}
            {Array.from({ length: 7 }).map((_, index) => (
              <div key={`text-${index}`} className="bg-slate-800/40 backdrop-blur-sm rounded-xl p-6 border border-slate-700/50 hover:bg-slate-800/60 transition-all">
                <h2 className="text-2xl text-white mb-4">Título {index + 4}</h2>
                <p className="text-white text-[12px] leading-relaxed">
                  Tu texto aquí
                </p>
              </div>
            ))}
          </div>
        </div>

        {/* Copy Box Sections */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {Array.from({ length: 10 }).map((_, index) => (
            <div key={`copy-${index}`} className="bg-slate-800/40 backdrop-blur-sm rounded-xl p-6 border border-slate-700/50 hover:bg-slate-800/60 transition-all">
              <h3 className="text-xl text-white mb-4">Copy Box {index + 1}</h3>
              <div className="bg-slate-900/80 rounded-lg p-4">
                <pre className="text-white text-[12px] whitespace-pre-wrap">
                  Tu texto aquí
                </pre>
              </div>
            </div>
          ))}
        </div>

        {/* Image + Text Sections */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {Array.from({ length: 6 }).map((_, index) => (
            <div key={`image-${index}`} className="bg-slate-800/40 backdrop-blur-sm rounded-xl p-6 border border-slate-700/50 hover:bg-slate-800/60 transition-all">
              <h3 className="text-xl text-white mb-4">Imagen {index + 1}</h3>
              <img 
                src={`/api/placeholder/500/300`} 
                alt={`Imagen ${index + 1}`} 
                className="rounded-lg mb-4 w-full"
              />
              <p className="text-white text-[12px] leading-relaxed">
                Tu texto aquí
              </p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default HowToDraftPleadings;
